from pathlib import Path
import torch, json, re
for fn in ['model.py','train.py','predict.py']:
    p=Path(fn)
    print(f'===== {fn} lines={sum(1 for _ in p.open())} bytes={p.stat().st_size} =====')
    txt=p.read_text()
    for pat in ['class ', 'def ', 'add_argument', 'torch.save', 'best', 'resume', 'roll', 'loss', 'scheduler', 'optimizer']:
        hits=[]
        for i,l in enumerate(txt.splitlines(),1):
            if pat in l:
                hits.append(f'{i}:{l[:160]}')
        if hits:
            print('---',pat,'---')
            print('\n'.join(hits[:40]))
    print()
print('===== checkpoints metadata =====')
for cp in Path('checkpoints').glob('*.pt'):
    ck=torch.load(cp,map_location='cpu',weights_only=False)
    print(cp, 'size', cp.stat().st_size)
    print(' keys', ck.keys())
    print(' args', ck.get('args'))
    for k in ['epoch','best_val','best_rmse_z500','val_rmse_z500','mean','std']:
        if k in ck: print(' ',k, ck[k])
